// Product detail page quatity selector

$(".js-qty-add, .js-qty-sub").on("click", function(ev) {
	console.log('clicked...');
  	var currentQty = $('.js-qty').val();
  	var qtyDirection = $(this).data("direction");
  	var newQty = 0;
  
  	if (qtyDirection == "1") {
    	newQty = parseInt(currentQty) + 1;
  	}
  	else if (qtyDirection == "-1") {
    	newQty = parseInt(currentQty) - 1;
  	}

  	// make decrement disabled at 1
  	if (newQty == 1) {
    	$(".js-qty-sub").attr("disabled", "disabled");
  	}
  
  	// remove disabled attribute on subtract
  	if (newQty > 1) {
    	$(".js-qty-sub").removeAttr("disabled");
  	}
  
  	if (newQty > 0) {
    	newQty = newQty.toString();
    	$('.js-qty').val(newQty);
  	}
  	else {
    	$('.js-qty').val("1");
  	}
});